};

function formatConsoleArgs(parts: unknown[]): string {
	return parts
		.map((p) => {
			if (typeof p === "string") return p;
			if (p === undefined) return "undefined";
			if (p === null) return "null";
			if (typeof p === "object") {
				try {
					return JSON.stringify(p);
				} catch {
					return String(p);
				}

